def generate_unique_random_numbers(start, end):
    generated_numbers = set()
    while len(generated_numbers) < 10:
        num = random.randint(start, end)
        if num not in generated_numbers:
            generated_numbers.add(num)
    return list(generated_numbers)

def print_generated_numbers(numbers):
    print("generated unique random numbers:")
    for i, num in enumerate(numbers, 1):
        print(f"number {i}: {num}")

def calculate_mean(numbers):
    return sum(numbers) / len(numbers)

def calculate_standard_deviation(numbers):
    mean = calculate_mean(numbers)
    return (sum((x - mean) ** 2 for x in numbers) / len(numbers)) ** 0.5

def main():
    start = 1
    end = 100
    numbers = generate_unique_random_numbers(start, end)
    print_generated_numbers(numbers)
    mean = calculate_mean(numbers)
    std_dev = calculate_standard_deviation(numbers)
